package com.chaobo.scm.supplier.infrastructure.persistence.qualification;
import com.chaobo.scm.supplier.application.qualification.SupplierQualificationApplicationService;import org.springframework.scheduling.annotation.Scheduled;import org.springframework.stereotype.Component;
@Component public class SupplierQualificationExpiryTask {private final MyBatisSupplierQualificationAdapter repository;private final SupplierQualificationApplicationService service;public SupplierQualificationExpiryTask(MyBatisSupplierQualificationAdapter repository,SupplierQualificationApplicationService service){this.repository=repository;this.service=service;}@Scheduled(cron="${scm.qualification.expire-cron:0 10 0 * * *}")public void expire(){for(long id:repository.expiredIds())service.expire(id);}}
